def _invoke_scene_director_batch(*, input_path: str, output_path: str, model: str) -> dict[str, Any]:
    batch_id = Path(input_path).stem.replace("_input", "")
    openclaw_bin = shutil.which("openclaw")
    if not openclaw_bin:
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "openclaw_cli_not_found", "message": "Cannot invoke scene_director: `openclaw` CLI not found in PATH."}],
            "warnings": [],
        }

    command = [
        openclaw_bin,
        "agent",
        "--agent",
        "op_s1_scene_director",
        "--message",
        _build_scene_director_agent_message(input_path, output_path),
        "--local",
        "--json",
    ]
    env = None

    try:
        result = subprocess.run(command, text=True, capture_output=True, check=False, timeout=300, env=env)
    except subprocess.TimeoutExpired:
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_timeout", "message": f"scene_director invocation timed out for batch {batch_id}."}],
            "warnings": [],
        }
    except Exception as exc:  # noqa: BLE001
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_invocation_failed", "message": f"scene_director invocation raised exception: {exc}"}],
            "warnings": [],
        }

    if result.returncode != 0:
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_nonzero_exit", "message": f"scene_director CLI exited with code {result.returncode}: {(result.stderr or result.stdout or '').strip()}"}],
            "warnings": [],
        }

    artifact_path = Path(output_path)
    candidates: list[str] = []
    warnings: list[dict[str, Any]] = []
    if artifact_path.exists():
        try:
            file_text = artifact_path.read_text(encoding="utf-8")
            if file_text.strip():
                candidates.append(file_text)
        except Exception:
            pass

    stdout_text = (result.stdout or "").strip()
    stderr_text = (result.stderr or "").strip()
    candidates.extend(_collect_json_candidates(stdout_text))
    candidates.extend(_collect_json_candidates(stderr_text))

    for candidate in candidates:
        parsed = _try_parse_json_candidate(candidate)
        if parsed is None:
            continue
        try:
            normalized = _normalize_scene_director_candidate(parsed, batch_id=batch_id)
            artifact_path.write_text(json.dumps(normalized, indent=2, ensure_ascii=False), encoding="utf-8")
            validation = validate_scene_director_output(
                batch_payload_path=input_path,
                batch_output_path=output_path,
            )
            if validation.get("approved_for_merge"):
                if candidate != stdout_text and stdout_text:
                    warnings.append({"code": "salvaged_scene_director_output", "message": f"Recovered valid scene_director JSON for {batch_id} from non-file candidate."})
                return {"batch_id": batch_id, "status": "completed", "output_path": output_path, "errors": [], "warnings": warnings}
        except Exception:
            continue

    if not artifact_path.exists():
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_no_output", "message": "scene_director invocation completed but no valid output artifact was produced."}],
            "warnings": warnings,
        }

    return {
        "batch_id": batch_id,
        "status": "failed",
        "output_path": output_path,
        "errors": [{"code": "operator_invalid_output", "message": "scene_director invocation completed but no valid JSON candidate passed validation."}],
        "warnings": warnings,
    }


