        "agent",
        "--agent",
        "op_s1_tts_polish",
        "--message",
        _build_tts_polish_agent_message(input_path, output_path),
        "--local",
        "--json",
    ]
    env = None

    try:
        result = subprocess.run(command, text=True, capture_output=True, check=False, timeout=300, env=env)
    except subprocess.TimeoutExpired:
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_timeout", "message": f"tts_polish invocation timed out for batch {batch_id}."}],
