        }
    except Exception as exc:  # noqa: BLE001
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_invocation_failed", "message": f"tts_polish invocation raised exception: {exc}"}],
            "warnings": [],
        }

    if result.returncode != 0:
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_nonzero_exit", "message": f"tts_polish CLI exited with code {result.returncode}: {(result.stderr or result.stdout or '').strip()}"}],
            "warnings": [],
        }

    if not Path(output_path).exists():
        stdout_text = (result.stdout or "").strip()
        if stdout_text:
            try:
                parsed = json.loads(stdout_text)
                Path(output_path).write_text(json.dumps(parsed, indent=2, ensure_ascii=False), encoding="utf-8")
