                pass

    if not Path(output_path).exists():
        return {
            "batch_id": batch_id,
            "status": "failed",
            "output_path": output_path,
            "errors": [{"code": "operator_no_output", "message": "tts_polish invocation completed but no output artifact was produced."}],
            "warnings": [],
        }

    return {"batch_id": batch_id, "status": "completed", "output_path": output_path, "errors": [], "warnings": []}


def _rewrite_tts_polish_batch_as_identity(
    *,
    batch_payload_path: str | Path,
    batch_output_path: str | Path,
    reason_codes: list[str] | None = None,
) -> dict[str, Any]:
    payload_path = Path(batch_payload_path)
    output_path = Path(batch_output_path)

    try:
        payload = json.loads(payload_path.read_text(encoding="utf-8"))
    except Exception as exc:  # noqa: BLE001
        return {
            "ok": False,
            "warnings": [],
            "errors": [{"code": "tts_polish_identity_fallback_payload_unreadable", "message": f"Failed to read payload for deterministic fallback: {exc}"}],
        }

    batch = payload.get("batch", {}) if isinstance(payload, dict) else {}
    scenes = payload.get("scenes", []) if isinstance(payload, dict) else []
    if not isinstance(scenes, list) or not scenes:
        return {
            "ok": False,
            "warnings": [],
            "errors": [{"code": "tts_polish_identity_fallback_invalid_payload", "message": "Cannot build deterministic fallback without payload scenes."}],
