def _run_scene_director_lane(
    *,
    run_root: Path,
    job: dict[str, Any],
    channel_config: dict[str, Any],
    paths: dict[str, Any],
    script_path: Path,
    script_raw: str,
    model: str,
    max_retries: int,
) -> dict[str, Any]:
    warnings: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []
    checkpoints_written: list[str] = []

    batch_plan = plan_script_batches_from_file(script_path)
    warnings.extend(batch_plan.get("warnings", []))
    if not batch_plan.get("ok"):
        return _lane_fail(batch_plan.get("errors", []), warnings)

    prepared_batches = []
    for batch in batch_plan.get("batches", []):
        batch_id = batch["batch_id"]
        input_path = Path(paths["scene_director_inputs_root"]) / f"{batch_id}_input.json"
        output_path = Path(paths["scene_director_intermediate_root"]) / f"{batch_id}_output.json"
        payload_result = write_scene_director_payload(
            run_root=run_root,
            job=job,
            batch=batch,
            channel_config=channel_config,
            input_path=input_path,
            output_path=output_path,
        )
        prepared_batches.append(
            {
                "batch_id": batch_id,
                "input_path": payload_result["input_path"],
                "output_path": payload_result["output_path"],
                "status": "queued",
            }
        )

    batch_lookup = {batch["batch_id"]: batch for batch in prepared_batches}
    approved_batch_files: dict[str, str] = {}
    failed_batch_ids: set[str] = set(batch_lookup.keys())
    attempt = 0

    while failed_batch_ids and attempt <= max_retries:
        attempt_batches = [batch_lookup[bid] for bid in prepared_batches_order(batch_lookup, failed_batch_ids)]
        schedule = build_batch_schedule(
            operator_name="scene_director",
            batches=attempt_batches,
            concurrency_cap=DEFAULT_SCENE_DIRECTOR_CONCURRENCY,
        )
        if not schedule.get("ok"):
            return _lane_fail(schedule.get("errors", []), warnings)

        execution_results = []
        for wave in schedule.get("waves", []):
            for batch in wave.get("batches", []):
                execution_results.append(
                    _invoke_scene_director_batch(
                        input_path=batch["input_path"],
                        output_path=batch["output_path"],
                        model=model,
                    )
                )

        execution_summary = summarize_batch_execution(
            operator_name="scene_director",
            concurrency_cap=DEFAULT_SCENE_DIRECTOR_CONCURRENCY,
            execution_results=execution_results,
        )
        warnings.extend(execution_summary.get("warnings", []))

        current_failed: set[str] = set()
        current_errors: list[dict[str, Any]] = []

        for batch in attempt_batches:
            batch_id = batch["batch_id"]
            output_path = Path(batch["output_path"])
            if not output_path.exists():
                current_failed.add(batch_id)
                current_errors.append(
                    {
                        "code": "missing_batch_output",
                        "message": f"scene_director did not produce output artifact for {batch_id}: {output_path}",
                    }
                )
                continue

            payload_data = json.loads(Path(batch["input_path"]).read_text(encoding="utf-8"))
            try:
                output_data = json.loads(output_path.read_text(encoding="utf-8"))
            except Exception as exc:  # noqa: BLE001
                current_failed.add(batch_id)
                current_errors.append(
                    {
                        "code": "invalid_batch_json",
                        "message": f"scene_director produced invalid JSON for {batch_id}: {exc}",
                    }
                )
                continue

            scene_words_range = payload_data.get("scene_words_range", {})
            if isinstance(scene_words_range, dict):
                min_words = scene_words_range.get("min")
                max_words = scene_words_range.get("max")
            elif isinstance(scene_words_range, list) and len(scene_words_range) >= 2:
                min_words, max_words = scene_words_range[0], scene_words_range[1]
            else:
                min_words, max_words = 35, 75

