                agent_output=output_data,
                original_text=payload_data["batch"]["text"],
                min_words=min_words,
                max_words=max_words,
                batch_id=batch_id,
            )
            if not reconstruct_result.get("ok"):
                current_failed.add(batch_id)
                current_errors.extend(reconstruct_result.get("errors", []))
                continue

            Path(batch["output_path"]).write_text(
                json.dumps(reconstruct_result["output"], indent=2, ensure_ascii=False),
                encoding="utf-8",
            )

            validation = validate_scene_director_output(
                batch_payload_path=batch["input_path"],
                batch_output_path=batch["output_path"],
            )
            if validation.get("approved_for_merge"):
